#[tokio::test]
async fn test_static_server_returns_index_html_for_directory() {
    // When index files are enabled the server should serve index.html when the directory root is requested.
    use axum::Router;
    use tower_http::services::ServeDir;
    let tmp_dir = tempfile::tempdir().expect("tmp dir");
    let mut router = Router::new();
    std::fs::write(tmp_dir.path().join("index.html"), r#"<!doctype html><h1>Welcome</h1>"#).unwrap();
    std::fs::create_dir_all(tmp_dir.path().join("styles")).unwrap();
    std::fs::write(tmp_dir.path().join("styles/main.css"), r#"h1 { color: #336699; }"#).unwrap();
    router = router.nest_service(
        "/app",
        ServeDir::new(tmp_dir.path()).append_index_html_on_directories(true),
    );
    let server = axum_test::TestServer::new(router);
    let response = server.get("/app/").await;
    assert_eq!(response.status_code().as_u16(), 200u16);
}
